import hashlib

def werkzeug_pin(username, modname, appname, file_path, mac_int, machine_id):
    h = hashlib.md5()
    for x in (username, modname, appname, file_path):
        if x:
            h.update(x.encode())
    h.update(b"cookiesalt")
    h.update(str(mac_int).encode())
    if machine_id:
        h.update(machine_id.encode())
    h.update(b"pinsalt")
    num = ("%09d" % (int(h.hexdigest(), 16) % 1000000000))
    return "-".join([num[i:i+3] for i in range(0, 9, 3)])

